function buildGFUrl(h, b) {
 const enc = n => encodeURIComponent(n).replace(/%20/g, '+');
 let url = 'https://fonts.googleapis.com/css2?family=' + enc(h) + ':wght@400;700';
 if (b && b !== h) url += '&family=' + enc(b) + ':wght@300;400;700';
 return url + '&display=swap';
}
Отдельная мелочь, которая бесила пару вечеров: ползунки размера шрифта и отступов «не тянулись». Оказалось, на каждое событие
input
я перерисовывал всю карточку целиком, и узел ползунка пересоздавался прямо под пальцем, драг рвался. Лечится точечным обновлением: меняем только нужные
textContent
и
